code.C:
#include <stdio.h>
#include <math.h>
int main(){
    long long n; if(scanf("%lld",&n)!=1) return 0;
    const double e = 2.71828182845904523536; // double precision
    long long ans = 0;
    for(long long i=1;i<=n;++i){
        ans += (long long)floor(i*e);
    }
    printf("%lld\n", ans);
    return 0;
}

