code.Python3:
#!/usr/bin/env python3
import sys, math

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    e = math.e  # double precision constant
    ans = 0
    for i in range(1, n + 1):
        ans += int(math.floor(i * e))
    print(ans)

if __name__ == "__main__":
    main()

